```csharp
public enum OrderStatus
{
    Pending,
    InProgress,
    Shipped,
    Delivered,
    Cancelled
}

public class OrderStatus : EnumBase<OrderStatus>
{
    public static OrderStatus FromString(string status)
    {
        return TryParse(status, out var value) ? value : OrderStatus.Pending;
    }

    public static bool TryParse(string status, out OrderStatus value)
    {
        if (Enum.TryParse(status, true, out var enumValue))
        {
            value = (OrderStatus)enumValue;
            return true;
        }
        value = OrderStatus.Pending;
        return false;
    }

    public bool IsPending() => this == OrderStatus.Pending;

    public bool IsShipped() => this == OrderStatus.Shipped;

    // Add more validation and logic as needed
}

