```csharp
public interface IBaseRepository<T> where T : class
{
    // ... other methods ...

    Task<T> FindByDynamicAsync(Expression<Func<T, bool>> expression, CancellationToken cancellationToken = default);
}

public abstract class BaseRepository<T> : IBaseRepository<T> where T : class
{
    private readonly DbContext _context;
    private readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    // ... other methods ...

    public virtual async Task<T> FindByDynamicAsync(Expression<Func<T, bool>> expression, CancellationToken cancellationToken = default)
    {
        return await _dbSet
            .Where(expression)
            .FirstOrDefaultAsync(cancellationToken);
    }
}
```

